# ── Session store (in-memory) ──────────────────────────────────────────────────
@dataclass
class SessionData:
    """Holds all state for one drafting session."""

    drafts: dict[str, PlatformDraft]  # keyed by Platform.value
    suggested_subreddits: list[str] = field(default_factory=list)
    created_at: datetime = field(default_factory=lambda: datetime.now(timezone.utc))
    last_accessed: datetime = field(default_factory=lambda: datetime.now(timezone.utc))

    def touch(self) -> None:
        """Update the last-accessed timestamp."""
        self.last_accessed = datetime.now(timezone.utc)


_sessions: dict[str, SessionData] = {}
_sessions_lock = threading.Lock()


def _create_session(
    drafts: list[PlatformDraft],
    suggested_subreddits: list[str] | None = None,
) -> str:
    """Store drafts (and optional subreddit suggestions) in a new session.

    Returns the session ID.
    """
    session_id = str(uuid.uuid4())
    data = SessionData(
        drafts={d.platform.value: d for d in drafts},
        suggested_subreddits=suggested_subreddits or [],
    )
    with _sessions_lock:
        _sessions[session_id] = data
    return session_id


def _get_session(session_id: str) -> SessionData:
    """Retrieve a session, updating its last-accessed time.

    Raises:
        HTTPException 404: If the session does not exist or has expired.
    """
    with _sessions_lock:
        session = _sessions.get(session_id)
    if session is None:
        raise HTTPException(status_code=404, detail="Session not found or expired.")
    session.touch()
    return session


def _evict_expired_sessions() -> None:
    """Remove sessions older than SESSION_TTL_MINUTES. Called by APScheduler."""
    cutoff = datetime.now(timezone.utc) - timedelta(minutes=settings.session_ttl_minutes)
    with _sessions_lock:
        expired = [sid for sid, s in _sessions.items() if s.last_accessed < cutoff]
        for sid in expired:
            del _sessions[sid]
    if expired:
        logger.info("Evicted %d expired session(s).", len(expired))


# ── App lifespan ───────────────────────────────────────────────────────────────
@asynccontextmanager
async def lifespan(app: FastAPI):  # noqa: ARG001
    """Start APScheduler and init the database on startup; stop on shutdown."""
    init_db()
    linkedin_auth.load_token()
    scheduler.add_job(
        _evict_expired_sessions,
        trigger="interval",
        minutes=30,
        id="session_eviction",
        replace_existing=True,
    )
    scheduler.start()
    logger.info("APScheduler started.")
    yield
    scheduler.shutdown(wait=False)
    logger.info("APScheduler stopped.")


